class HelpFunctions:
    @staticmethod
    def get_base_url(url: str) -> str:
        parsed_url = urlparse(url)
        return (
            f"{parsed_url.scheme}://{parsed_url.netloc}"
            if parsed_url.scheme and parsed_url.netloc
            else url
        )

    @staticmethod
    def remove_emojis(text: str) -> str:
        return "".join(c for c in text if not unicodedata.category(c).startswith("So"))

    @staticmethod
    def truncate_to_n_words(text: str, token_limit: int) -> str:
        if not text or not isinstance(text, str):
            return ""
        tokens = text.split()
        return " ".join(tokens[:token_limit])

    @staticmethod
    def count_words(text: str) -> int:
        if not text or not isinstance(text, str):
            return 0
        return len(text.split())

    @staticmethod
    def _normalize_spaces(s: str) -> str:
        if not isinstance(s, str):
            return ""
        return (
            s.replace("\u00a0", " ")
            .replace("\u202f", " ")
            .replace("\u2007", " ")
            .replace("\u200b", "")
            .replace("\ufeff", "")
        )

    @staticmethod
    def _html_to_md(html: str) -> str:
        try:
            return HelpFunctions._normalize_spaces(
                md(html, heading_style="ATX", strip=["script", "style"], bullets="*")
                or ""
            )
        except Exception:
            txt = re.sub(r"(?is)<(script|style).*?>.*?</\\1>", "", html or "")
            txt = re.sub(r"(?is)<br\\s*/?>", "\n", txt)
            txt = re.sub(r"(?is)</p>", "\n\n", txt)
            txt = re.sub(r"(?is)<[^>]+>", "", txt)
            return HelpFunctions._normalize_spaces(txt)

    @staticmethod
    def _to_jina(u: str) -> str:
        if u.startswith(("https://r.jina.ai/", "http://r.jina.ai/")):
            return u
        if u.startswith("https://"):
            return "https://r.jina.ai/https://" + u[len("https://") :]
        if u.startswith("http://"):
            return "https://r.jina.ai/http://" + u[len("http://") :]
        return "https://r.jina.ai/https://" + u

    @staticmethod
    async def fetch_jina_text(
        session: aiohttp.ClientSession, url: str, timeout: int = 30
    ) -> str:
        try:
            rj = await session.get(HelpFunctions._to_jina(url), timeout=timeout)
            try:
                txt = await rj.text(encoding="utf-8", errors="ignore")
            finally:
                await rj.release()
            return HelpFunctions._normalize_spaces(txt or "")
        except Exception:
            return ""

    @staticmethod
    def looks_like_pdf(content_type: str, url: str) -> bool:
        ctype = (content_type or "").lower()
        return ("application/pdf" in ctype) or (url.lower().endswith(".pdf"))

    @staticmethod
    def extract_from_html(html: str, url: Optional[str] = None) -> str:
        if not html:
            return ""
        raw_html = html
        content_html = None
        try:
            content_html = trafilatura.extract(
                raw_html,
                url=url,
                include_comments=True,
                include_tables=True,
                output_format="html",
                target_language=None,
            )
        except Exception:
            content_html = None

        content_txt = None
        if not content_html:
            try:
                content_txt = trafilatura.extract(
                    raw_html,
                    url=url,
                    include_comments=True,
                    include_tables=True,
                    output_format="txt",
                    target_language=None,
                )
            except Exception:
                content_txt = None

        if not content_html and not content_txt:
            try:
                bex = trafilatura.bare_extractor(raw_html, url=url)
                if bex and bex.get("text"):
                    content_txt = bex["text"]
            except Exception:
                pass

        if content_html:
            return HelpFunctions._html_to_md(content_html)
        if content_txt:
            return HelpFunctions._normalize_spaces(content_txt)
        return HelpFunctions._html_to_md(raw_html)

    @staticmethod
    def extract_text_from_pdf_bytes(data: bytes) -> str:
        if not data:
            return ""
        try:
            from pdfminer.high_level import extract_text as _pdf_extract_text

            buf = io.BytesIO(data)
            txt = _pdf_extract_text(buf) or ""
            return HelpFunctions._normalize_spaces(txt)
        except Exception:
            return ""

    @staticmethod
    def format_text(original_text: str) -> Optional[str]:
        try:
            extracted = HelpFunctions.extract_from_html(original_text)
            if extracted and extracted.strip():
                return extracted.strip()
        except Exception:
            pass
        try:
            soup = BeautifulSoup(original_text, "html.parser")
            formatted_text = soup.get_text(separator=" ", strip=True)
            formatted_text = unicodedata.normalize("NFKC", formatted_text)
            formatted_text = re.sub(r"\s+", " ", formatted_text).strip()
            return formatted_text if formatted_text else None
        except Exception:
            return original_text

    @staticmethod
    def format_text_md(original_text: str) -> Optional[str]:
        try:
            extracted = HelpFunctions.extract_from_html(original_text)
            if extracted and extracted.strip():
                return extracted.strip()
        except Exception:
            pass
        return HelpFunctions.format_text(original_text)


class EventEmitter:
    def __init__(self, event_emitter: Optional[Callable[[dict], Any]] = None):
        self.event_emitter = event_emitter

    async def emit(
        self,
        description: str = "Unknown State",
        status: str = "in_progress",
        done: bool = False,
        step_number: Optional[int] = None,
    ) -> None:
        if self.event_emitter:
            message = {
                "type": "status",
                "data": {"status": status, "description": description, "done": done},
            }
            if step_number is not None:
                message["data"]["step"] = step_number
            await self.event_emitter(message)


class Filter:
    class Valves(BaseModel):
        SEARXNG_ENGINE_API_BASE_URL: str = Field(
            default="http://127.0.0.1:8080/search",
            description="The base URL for Search Engine",
        )
        SEARXNG_QUERIES_MIN: int = Field(
            default=4, description="Minimum relevant search queries"
        )
        SEARXNG_QUERIES_MAX: int = Field(
            default=4, description="Maximum relevant search queries"
        )
        SEARXNG_ENGINES: str = Field(
            default="google,duckduckgo,brave,yandex,wikidata,wikipedia",
            description="Comma-separated list of search engines",
        )
        IGNORED_WEBSITES: str = Field(
            default=(
                "youtube.com, ask.com, questionsanswered.net, linkedin.com, simpli.com, faqtoids.com, "
                "reference.com, consumersearch.com, smarter.com, meetup.com, ria.ru, narod.co.il, addmeto.cc, "
                "mobiset.ru, flixbus.sk, flixbus.com, flixbus.ca, tampanails.com, scmp.com, facebook.com, "
                "prestigefootballschools.com, instagram.com, support.google.com, google.co.uk, kinopoisk.ru, "
                "kita.de, kita4.info, zhihu.com"
            ),
            description="Comma-separated list of websites to ignore",
        )
        RETURNED_SCRAPPED_PAGES_NO: int = Field(
            default=30, description="Number of SERP items to parse"
        )
        SCRAPPED_PAGES_NO: int = Field(default=20, description="Total pages scraped")
        PAGE_CONTENT_WORDS_LIMIT: int = Field(
            default=3000, description="Per-page words cap"
        )
        GLOBAL_CONTENT_WORDS_LIMIT: int = Field(
            default=16000, description="Global words cap"
        )
        CITATION_LINKS: bool = Field(
            default=True, description="Emit citations events with links"
        )
        REQUEST_TIMEOUT: int = Field(
            default=10, description="Timeout for HTTP requests in seconds"
        )
        MAX_CONCURRENT_REQUESTS: int = Field(
            default=5, description="Max concurrent HTTP requests"
        )

    def __init__(self):
        self.valves = self.Valves()
        self.toggle = True
        self.icon = ""
        self.headers = {
            "User-Agent": (
                "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 "
                "(KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"
            ),
            "Accept": "text/html,application/xhtml+xml,application/xml,application/pdf;q=0.9,*/*;q=0.8",
            "Accept-Language": "en,ru;q=0.9",
            "Cache-Control": "no-cache",
            "Pragma": "no-cache",
        }
        self.functions = HelpFunctions()
        self._ignored_domains_cache = None
        self._session: Optional[aiohttp.ClientSession] = None

    @property
    def ignored_domains(self) -> List[str]:
        if self._ignored_domains_cache is None:
            self._ignored_domains_cache = [
                d.strip().lower()
                for d in self.valves.IGNORED_WEBSITES.split(",")
                if d.strip()
            ]
        return self._ignored_domains_cache

    async def get_session(self) -> aiohttp.ClientSession:
        if self._session is None or self._session.closed:
            timeout = aiohttp.ClientTimeout(total=self.valves.REQUEST_TIMEOUT)
            self._session = aiohttp.ClientSession(headers=self.headers, timeout=timeout)
        return self._session

    async def close_session(self):
        if self._session and not self._session.closed:
            await self._session.close()

    def __del__(self):
        if hasattr(self, "_session") and self._session and not self._session.closed:
            try:
                asyncio.create_task(self._session.close())
            except RuntimeError:
                pass

    async def process_search_result_async(
        self, result: dict, session: aiohttp.ClientSession
    ) -> Optional[dict]:
        title_site = self.functions.remove_emojis(result.get("title", ""))
        url_site = result.get("url", "")
        snippet = result.get("content", "")

        parsed_url = urlparse(url_site)
        domain = parsed_url.netloc.lower() if parsed_url.netloc else ""
        if any(ignored in domain for ignored in self.ignored_domains):
            return None

        try:
            async with session.get(url_site) as response:
                content_type = response.headers.get("content-type", "").lower()

                if self.functions.looks_like_pdf(content_type, url_site):
                    text = await self.functions.fetch_jina_text(session, url_site)
                    if not text:
                        pdf_bytes = await response.read()
                        loop = asyncio.get_running_loop()
                        text = await loop.run_in_executor(
                            None, self.functions.extract_text_from_pdf_bytes, pdf_bytes
                        )
                else:
                    html_content = await response.text(
                        encoding="utf-8", errors="ignore"
                    )
                    text = self.functions.format_text_md(html_content) or ""

                if not text or not text.strip():
                    text = snippet if snippet else "Failed to extract content"

                truncated = self.functions.truncate_to_n_words(
                    text, self.valves.PAGE_CONTENT_WORDS_LIMIT
                )

                content_dict = {
                    "title": title_site,
                    "url": url_site,
                    "content": truncated,
                    "snippet": self.functions.remove_emojis(snippet),
                    "engine": result.get("engine", ""),
                    "search_query": result.get("search_query", ""),
                }

                await asyncio.sleep(0)
                return content_dict

        except (aiohttp.ClientError, asyncio.TimeoutError):
            return None
        except Exception:
            return None

    async def search_web(
        self, query: str, __event_emitter__: Optional[Callable[[dict], Any]] = None
    ) -> str:
        emitter = EventEmitter(__event_emitter__)

        await emitter.emit("🔍 Starting web search", step_number=1)
        await emitter.emit(f"📝 Search query: {query}", step_number=2)

        if self.valves.RETURNED_SCRAPPED_PAGES_NO > self.valves.SCRAPPED_PAGES_NO:
            self.valves.RETURNED_SCRAPPED_PAGES_NO = self.valves.SCRAPPED_PAGES_NO

        params = {
            "q": query,
            "engines": self.valves.SEARXNG_ENGINES,
            "format": "json",
            "number_of_results": self.valves.SCRAPPED_PAGES_NO,
        }

        try:
            await emitter.emit("🌐 Connecting to the search engine", step_number=4)
            resp = requests.get(
                self.valves.SEARXNG_ENGINE_API_BASE_URL,
                params=params,
                headers=self.headers,
                timeout=self.valves.REQUEST_TIMEOUT,
            )
            resp.encoding = "utf-8"
            resp.raise_for_status()
            data = resp.json()
            raw_results = data.get("results", [])

            filtered_results = []
            for res in raw_results:
                url = res.get("url", "")
                parsed = urlparse(url)
                dom = parsed.netloc.lower() if parsed.netloc else ""
                if not any(ignored in dom for ignored in self.ignored_domains):
                    filtered_results.append(res)

            limited_results = filtered_results[: self.valves.SCRAPPED_PAGES_NO]
            await emitter.emit(
                f"📊 Found {len(limited_results)} results", step_number=5
            )

        except requests.exceptions.RequestException as e:
            await emitter.emit(
                status="error",
                description=f"❌ Error during search: {str(e)}",
                done=True,
            )
            return json.dumps({"error": str(e)})

        final_results: List[dict] = []
        total_words = 0
        global_cap = max(0, int(self.valves.GLOBAL_CONTENT_WORDS_LIMIT))
        cap_reached = False

        if limited_results and global_cap > 0:
            await emitter.emit("🔄 Processing search results", step_number=6)

            session = await self.get_session()
            semaphore = asyncio.Semaphore(self.valves.MAX_CONCURRENT_REQUESTS)

            async def worker(res):
                async with semaphore:
                    return await self.process_search_result_async(res, session)

            tasks = [asyncio.create_task(worker(result)) for result in limited_results]
            processed_count = 0
            total = len(limited_results)

            try:
                for coro in asyncio.as_completed(tasks):
                    item = await coro
                    if not item:
                        continue
                    page_words = self.functions.count_words(item.get("content", ""))

                    if total_words >= global_cap:
                        cap_reached = True
                        break

                    if total_words + page_words <= global_cap:
                        final_results.append(item)
                        total_words += page_words
                    else:
                        remaining = max(0, global_cap - total_words)
                        if remaining > 0:
                            trimmed = self.functions.truncate_to_n_words(
                                item.get("content", ""), remaining
                            )
                            item["content"] = trimmed
                            final_results.append(item)
                            total_words += self.functions.count_words(trimmed)
                        cap_reached = True
                        for t in tasks:
                            if not t.done():
                                t.cancel()
                        break

                    processed_count += 1
                    try:
                        u = item.get("url", "")
                        clean_domain = urlparse(u).netloc if u else ""
                    except Exception:
                        clean_domain = ""
                    await emitter.emit(
                        f"📄 Processing page {processed_count}/{total}: {clean_domain}",
                        step_number=7,
                    )

            except asyncio.CancelledError:
                cap_reached = True
            finally:
                for t in tasks:
                    if not t.done():
                        t.cancel()

            if cap_reached:
                await emitter.emit("🛑 Content words limit reached.", step_number=8)

            if self.valves.CITATION_LINKS and __event_emitter__:
                await emitter.emit("📚 Generating citations and links", step_number=9)
                for result in final_results:
                    await __event_emitter__(
                        {
                            "type": "citation",
                            "data": {
                                "document": [result["content"]],
                                "metadata": [
                                    {
                                        "source": result["url"],
                                        "date_accessed": datetime.now().isoformat(),
                                        "title": result["title"],
                                    }
                                ],
                                "source": {
                                    "name": result["title"],
                                    "url": result["url"],
                                },
                            },
                        }
                    )

        await emitter.emit(
            status="complete",
            description=(
                f"✅ Search completed - processed {len(final_results)} pages; total words: "
                f"{total_words}/{self.valves.GLOBAL_CONTENT_WORDS_LIMIT}"
            ),
            done=True,
            step_number=10,
        )

        return json.dumps(final_results, ensure_ascii=False)

    async def search_multiple_queries(
        self,
        queries: List[str],
        __event_emitter__: Optional[Callable[[dict], Any]] = None,
    ) -> str:
        emitter = EventEmitter(__event_emitter__)

        if not queries:
            return json.dumps([])

        await emitter.emit(f"🔍 Searching {len(queries)} queries", step_number=1)

        all_query_results: List[List[dict]] = []

        for i, query in enumerate(queries, 1):
            await emitter.emit(f"📝 Search: {query}", step_number=i + 1)

            params = {
                "q": query,
                "engines": self.valves.SEARXNG_ENGINES,
                "format": "json",
                "number_of_results": self.valves.SCRAPPED_PAGES_NO,
            }

            try:
                resp = requests.get(
                    self.valves.SEARXNG_ENGINE_API_BASE_URL,
                    params=params,
                    headers=self.headers,
                    timeout=self.valves.REQUEST_TIMEOUT,
                )
                resp.encoding = "utf-8"
                resp.raise_for_status()
                data = resp.json()

                raw_results = data.get("results", [])

                filtered_results = []
                for res in raw_results:
                    url = res.get("url", "")
                    parsed_url = urlparse(url)
                    domain = parsed_url.netloc.lower()
                    if not any(ignored in domain for ignored in self.ignored_domains):
                        res["search_query"] = query
                        filtered_results.append(res)

                limited_results = filtered_results[: self.valves.SCRAPPED_PAGES_NO]
                all_query_results.append(limited_results)

            except requests.exceptions.RequestException as e:
                await emitter.emit(f"❌ Error in request {i}: {str(e)}")
                all_query_results.append([])

        selected_results: List[dict] = []
        seen_urls = set()
        max_results_per_query = max((len(r) for r in all_query_results), default=0)

        for index in range(max_results_per_query):
            for query_results in all_query_results:
                if len(selected_results) >= self.valves.RETURNED_SCRAPPED_PAGES_NO:
                    break
                if index < len(query_results):
                    result = query_results[index]
                    url = result.get("url", "")
                    if url and url not in seen_urls:
                        seen_urls.add(url)
                        selected_results.append(result)
            if len(selected_results) >= self.valves.RETURNED_SCRAPPED_PAGES_NO:
                break

        final_results: List[dict] = []
        total_words = 0
        global_cap = max(0, int(self.valves.GLOBAL_CONTENT_WORDS_LIMIT))
        cap_reached = False

        if selected_results and global_cap > 0:
            await emitter.emit("🔄 Processing page content")

            session = await self.get_session()
            semaphore = asyncio.Semaphore(self.valves.MAX_CONCURRENT_REQUESTS)

            async def worker(res):
                async with semaphore:
                    return await self.process_search_result_async(res, session)

            tasks = [asyncio.create_task(worker(result)) for result in selected_results]

            try:
                for coro in asyncio.as_completed(tasks):
                    item = await coro
                    if not item:
                        continue
                    page_words = self.functions.count_words(item.get("content", ""))

                    if total_words >= global_cap:
                        cap_reached = True
                        break
                    if total_words + page_words <= global_cap:
                        final_results.append(item)
                        total_words += page_words
                    else:
                        remaining = max(0, global_cap - total_words)
                        if remaining > 0:
                            trimmed = self.functions.truncate_to_n_words(
                                item.get("content", ""), remaining
                            )
                            item["content"] = trimmed
                            final_results.append(item)
                            total_words += self.functions.count_words(trimmed)
                        cap_reached = True
                        for t in tasks:
                            if not t.done():
                                t.cancel()
                        break

                    try:
                        u = item.get("url", "")
                        clean_domain = urlparse(u).netloc if u else ""
                    except Exception:
                        clean_domain = u
                    await emitter.emit(f"📄 Viewed: {clean_domain}")
            except asyncio.CancelledError:
                cap_reached = True
            finally:
                for t in tasks:
                    if not t.done():
                        t.cancel()

            if cap_reached:
                await emitter.emit("🛑 Content words limit reached")

        if self.valves.CITATION_LINKS and __event_emitter__:
            await emitter.emit("📚 Generating citations and links")
            for result in final_results:
                await __event_emitter__(
                    {
                        "type": "citation",
                        "data": {
                            "document": [result["content"]],
                            "metadata": [
                                {
                                    "source": result["url"],
                                    "date_accessed": datetime.now().isoformat(),
                                    "title": result["title"],
                                    "search_query": result.get("search_query", ""),
                                }
                            ],
                            "source": {"name": result["title"], "url": result["url"]},
                        },
                    }
                )

        await emitter.emit(
            status="complete",
            description=f"✅ Search completed - processed {len(final_results)} pages",
            done=True,
        )

        return json.dumps(final_results, ensure_ascii=False)

    @staticmethod
    def get_text_from_message(msg: dict) -> str:
        content = msg.get("content", "")
        if isinstance(content, str):
            return content
        if isinstance(content, list):
            return " ".join(
                part.get("text", "") for part in content if part.get("type") == "text"
            )
        return ""

    @staticmethod
    def build_chat_history(messages: List[dict], limit: int = 5) -> str:
        chat_history = ""
        for msg in messages[-limit:]:
            role = msg.get("role", "")
            if role in ["user", "assistant"]:
                try:
                    content = Filter.get_text_from_message(msg).strip()
                    if content:
                        chat_history += f"{role.upper()}: {content}\n"
                except Exception:
                    continue
        return chat_history

    @staticmethod
    def clean_json_response(response_text: str) -> str:
        json_match = re.search(r"\{.*\}", response_text, re.DOTALL)
        return json_match.group(0) if json_match else response_text

    @staticmethod
    def safe_json_parse(response_text: str) -> dict:
        try:
            return json.loads(response_text)
        except json.JSONDecodeError:
            try:
                cleaned = Filter.clean_json_response(response_text)
                return json.loads(cleaned)
            except json.JSONDecodeError:
                return {"queries": []}

    async def inlet(
        self,
        body: dict,
        __event_emitter__,
        __user__: Optional[dict] = None,
        __event_call__=None,
        __request__=None,
    ) -> dict:
        messages = body.get("messages", [])
        if not messages:
            return body

        last_user_message = None
        for msg in reversed(messages):
            if msg.get("role") == "user":
                last_user_message = msg
                break
        if not last_user_message:
            return body

        emitter = EventEmitter(__event_emitter__)
        await emitter.emit("🔍 Generating search queries", step_number=1)

        user_query = self.get_text_from_message(last_user_message)
        chat_history = self.build_chat_history(messages)

        model = body.get("model", "")
        today = datetime.now()
        formatted_date = today.strftime("%Y-%m-%d")

        search_prompt = f"""### Task:
Analyze the chat history to determine the necessity of generating search queries. By default, **prioritize generating {self.valves.SEARXNG_QUERIES_MIN}-{self.valves.SEARXNG_QUERIES_MAX} broad and relevant search queries** unless it is absolutely certain that no additional information is required. The aim is to retrieve comprehensive, updated, and valuable information even with minimal uncertainty. If no search is unequivocally needed, return an empty list.

### Guidelines:
- Respond **EXCLUSIVELY** with a JSON object. Any form of extra commentary, explanation, or additional text is strictly prohibited.
- When generating search queries, respond in the format: {{ "queries": ["query1", "query2"] }}, ensuring each query is distinct, concise, and relevant to the topic.
- If and only if it is entirely certain that no useful results can be retrieved by a search, return: {{ "queries": [] }}.
